void resolver(std::vector<int>& accidentes) {
    // Ordenar el vector
    std::sort(accidentes.begin(), accidentes.end());
    // Inicializar variables para encontrar la moda
    int moda = accidentes[0];
    int max_count = 1, count = 1;
    // Recorrer el vector
    for (size_t i = 1; i < accidentes.size(); ++i) {
        // Comprobar si el elemento actual es igual al anterior
        if (accidentes[i] == accidentes[i - 1]) {
            count++;
        } else {
            count = 1;
        }
        // Actualizar la moda si se encuentra un segmento más largo
        if (count > max_count) {
            max_count = count;
            moda = accidentes[i];
        }
    }
    // Devolver la moda
    std::cout << moda << std::endl;
}

